MT::Combinatorics c(N, mod);
struct node {
	int now, to;
	ldb c;
	bool operator<(const node& a)const {
		return a.c < c;
	}
};
ldb pre[5005];
void init() {
	fa(i, 1, 5000)pre[i] += pre[i - 1] + logl(i);
}
void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<int>(n + 1);
	fa(i, 1, n)cin >> a[i];
	sort(all1(a));
	var Q = priority_queue<node>();
	fa(i, 2, n) {
		int n = a[i], m = a[i - 1];
		ldb now = pre[n] - pre[m] - pre[n - m];
		Q.push({ i - 1,i,now });
	}

	var s = vector<int>(n + 1);
	fa(i, 1, n)s[i] = i;
	var find = [&](var find, int x)->int {
		if (s[x] == x)return s[x];
		return s[x] = find(find, s[x]);
		};

  	ll ans = 0, cnt = n - 1;
	while (Q.size() and cnt) {
		var[now, to, _] = Q.top();
		Q.pop();

		int e1 = find(find, now), e2 = find(find, to);
		if (e1 != e2) {
			s[e2] = e1;
			cnt--;
			ans += c.C(max(a[now], a[to]), min(a[now], a[to]));
			ans %= mod;
		}

		if (to != n) {
			to++;
			int n = max(a[now], a[to]), m = min(a[now], a[to]);
			ldb C = pre[n] - pre[m] - pre[n - m];
			Q.push({ now, to, C });
		}
	}

	cout << ans << endl;
	return;
}
